def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(1, 5):
                for b in range(1, 7):
                    priority += ((ratio - a) ** (b)) / (a + b) * np.sin(ratio * a * b) * np.exp(-ratio / (b + 1))
            priority += (np.cosh(ratio - 7) - 1) * np.log1p(item + bin_cap)
        elif 5 < ratio <= 7:
            sum1 = 0
            for c in range(2, 12):
                for d in range(1, c):
                    val = ((ratio - 5) ** d) / (c * d + 1) * np.tanh((item + bin_cap) / (c + d))
                    sum1 += np.cos(val * ratio * d)
            priority = sum1 * np.log(ratio + 1) * 3
            for e in range(1, 4):
                priority += np.sin(ratio * e * i) / (e + 0.5)
        elif 3 <= ratio <= 5:
            s = 0
            for f in range(1, 15):
                if f % 2 == 0:
                    s += ((ratio - 3) ** f) / (f ** 2 + 1) * np.cos(f * ratio * 1.3)
                else:
                    s += ((ratio - 3) ** f) / (f + 1) * np.sin(f * ratio * 0.7)
            priority = s - np.log(ratio) * 5 + np.tanh(bin_cap / (item + 0.1)) * 2
            if bin_cap < item * 1.3:
                priority += np.exp(-ratio) * 4
            else:
                priority -= np.sqrt(bin_cap) * 1.7
        elif 1.2 <= ratio < 3:
            s = 0
            for g in range(1, 10):
                s += ((3 - ratio) ** g) / (g * 2 + 1) * np.cos(ratio * g * 0.9)
                if g % 3 == 0:
                    s += np.log1p(item + bin_cap) / (g + 0.5)
            penalty = 0
            if bin_cap < item * 0.9:
                penalty = np.sqrt(item / (bin_cap + 0.1)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3.2
            priority = s + penalty + np.exp(-2 / (ratio + 0.01))
            for h in range(1, 6):
                priority += np.sin(h * ratio * i * 1.3) * ((ratio - 1.2) ** h) / (h + 1)
        elif 0.5 <= ratio < 1.2:
            s = 0
            for j in range(1, 20):
                power = (1.2 - ratio) ** j
                s += power / (j * 3) * np.sin(j * item * 1.1)
            if (i * int(item * 2)) % 3 == 0:
                s *= np.log1p(bin_cap + 2.7) * 1.5
            else:
                s /= (np.sqrt(bin_cap + 2) + 1)
            priority = s
            for k in range(1, 7):
                priority += ((1.2 - ratio) ** k) * np.cos(k * item * 1.4) * 0.8
            if bin_cap < item * 0.5:
                priority += np.log1p(item * bin_cap) * 3.7
            else:
                priority -= np.exp(-ratio * 1.3) * 4.1
        elif 0.2 <= ratio < 0.5:
            s = 0
            for l in range(1, 18):
                s += ((0.5 - ratio) ** l) / (l * 4) * np.cos(l * ratio * 1.5)
            priority = s + 1 / (bin_cap + 2.5)
            if (int(item * 1.5) + i) % 5 == 0:
                priority *= 2.2
            else:
                priority /= 2.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 4.5
            else:
                priority -= np.exp(-ratio * 1.5) * 3.5
            for m in range(1, 8):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.sin(item * m * 1.2)
        else:
            s = 0
            for n in range(1, 12):
                s += ((0.2 - ratio) ** n) / (n * 6) * np.sin(n * item * 0.85)
            priority = s + 3 / (bin_cap + 3.5)
            if int(item * 0.9) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 4.8
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for o in range(1, 9):
                priority += ((0.2 - ratio) ** o) / (o * 8) * np.cos(item * o * 0.75)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6
            for p in range(1, 4):
                priority += np.sin(ratio * i * p) * (p * 0.4)
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
            for q in range(1, 5):
                if (i + q) % 2 == 0:
                    priority += np.cos(ratio * (i + q)) * 0.5
                else:
                    priority -= np.sin(ratio * (i + q)) * 0.5
        for r in range(1, 5):
            if (i + r) % 5 == 0:
                priority += np.sin(ratio * (i + r) * 1.2) * 0.45
            else:
                priority -= np.cos(ratio * (i + r) * 1.2) * 0.45
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.75
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.75
        priorities[i] = priority
    return priorities
